const express = require('express');
const app = express();

app.use(express.json());

// VULNERABLE: Normal object allows prototype pollution
app.post('/api/config/vulnerable', (req, res) => {
  const config = {};
  // This allows pollution via __proto__ or constructor.prototype
  Object.assign(config, req.body);

  res.json({ message: 'Config updated', config });
});

// SECURE: Object without prototype chain
app.post('/api/config/secure', (req, res) => {
  // Create object with null prototype - no inheritance
  const config = Object.create(null);

  // Safe merge - even if req.body contains __proto__, it's treated as regular property
  Object.assign(config, req.body);

  res.json({ message: 'Config updated securely', config });
});

// SECURE: Recursive safe merge for nested objects
function safeMerge(target, source) {
  const result = Object.create(null);

  // Only copy own properties from source
  Object.keys(source).forEach(key => {
    // Block dangerous keys
    if (['__proto__', 'constructor', 'prototype'].includes(key)) {
      return;
    }

    if (source[key] && typeof source[key] === 'object' && !Array.isArray(source[key])) {
      result[key] = safeMerge(Object.create(null), source[key]);
    } else {
      result[key] = source[key];
    }
  });

  return result;
}

app.post('/api/settings', (req, res) => {
  const settings = safeMerge(Object.create(null), req.body);
  res.json({ message: 'Settings merged safely', settings });
});

app.listen(3000, () => console.log('Server running on port 3000'));

