// Freeze prototypes at application startup (before any user input)
if (Object.freeze) {
  Object.freeze(Object.prototype);
  Object.freeze(Object);
  Object.freeze(Array.prototype);
  Object.freeze(Array);
  Object.freeze(Function.prototype);
  Object.freeze(Function);
  console.log('✓ Prototypes frozen - pollution attempts will throw in strict mode');
