// Option 2: Manual validation before lodash merge
const _ = require('lodash');

function validateNoPrototypePollution(obj, path = '') {
  if (!obj || typeof obj !== 'object') {
    return true;
  }

  const dangerousKeys = ['__proto__', 'constructor', 'prototype'];

  for (const key in obj) {
    if (!obj.hasOwnProperty(key)) continue;

    const currentPath = path ? `${path}.${key}` : key;

    // Block dangerous keys
    if (dangerousKeys.includes(key)) {
      throw new Error(`Prototype pollution attempt detected at path: ${currentPath}`);
    }

    // Recursively validate nested objects
    if (obj[key] && typeof obj[key] === 'object') {
      validateNoPrototypePollution(obj[key], currentPath);
    }
  }

  return true;
}

app.post('/api/merge/validated', (req, res) => {
  try {
    // Validate input before merging
    validateNoPrototypePollution(req.body);

    const target = { settings: { theme: 'dark' } };
    const merged = _.merge(target, req.body);

    res.json({ success: true, data: merged });
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

// Option 3: Middleware for global protection
function antiPrototypePollutionMiddleware(req, res, next) {
  if (req.body && typeof req.body === 'object') {
    try {
      validateNoPrototypePollution(req.body);
      next();
    } catch (error) {
      return res.status(400).json({ 
        error: 'Invalid request',
        message: 'Request contains potentially malicious payload'
      });
    }
  } else {
    next();
  }
}

// Apply middleware globally
app.use(antiPrototypePollutionMiddleware);

app.listen(3000, () => console.log('Server running with prototype pollution protection'));

const express = require('express');
const Ajv = require('ajv'); // npm install ajv
const app = express();

app.use(express.json());

// Initialize AJV with strict mode
const ajv = new Ajv({
  strict: true,
  removeAdditional: 'all', // Remove properties not in schema
  useDefaults: true,
  coerceTypes: false,
  allErrors: true
});

// Define strict schema - ONLY these properties allowed
const userSchema = {
  type: 'object',
  properties: {
    username: { type: 'string', minLength: 3, maxLength: 30 },
    email: { type: 'string', format: 'email' },
    age: { type: 'integer', minimum: 18, maximum: 120 },
    preferences: {
      type: 'object',
      properties: {
        theme: { type: 'string', enum: ['light', 'dark'] },
        notifications: { type: 'boolean' }
      },
      additionalProperties: false // Critical: block unknown properties
    }
  },
  required: ['username', 'email'],
  additionalProperties: false // Critical: reject __proto__, constructor, etc.
};

const validateUser = ajv.compile(userSchema);

// Middleware factory for schema validation
function validateSchema(schema) {
  const validate = ajv.compile(schema);

  return (req, res, next) => {
    const valid = validate(req.body);

    if (!valid) {
      return res.status(400).json({
        error: 'Validation failed',
        details: validate.errors.map(err => ({
          field: err.instancePath || 'root',
          message: err.message,
          params: err.params
        }))
      });
    }

    next();
  };
}

app.post('/api/user', validateSchema(userSchema), (req, res) => {
  // req.body is now guaranteed to match schema
  // __proto__ and other dangerous properties are stripped
  const user = req.body;

  res.json({ 
    success: true, 
    message: 'User created',
    user 
  });
});

// Alternative: express-validator
const { body, validationResult } = require('express-validator');

app.post('/api/settings',
  // Define exact fields and validation rules
  body('theme').isIn(['light', 'dark']),
  body('language').isLength({ min: 2, max: 2 }),
  body('autoSave').isBoolean(),

  // Custom validator to block dangerous keys
  body().custom((value) => {
    const dangerousKeys = ['__proto__', 'constructor', 'prototype'];
    const checkKeys = (obj, path = '') => {
      for (const key in obj) {
        if (dangerousKeys.includes(key)) {
          throw new Error(`Forbidden property: ${key}`);
        }
        if (obj[key] && typeof obj[key] === 'object') {
          checkKeys(obj[key], `${path}.${key}`);
        }
      }
    };
    checkKeys(value);
    return true;
  }),

  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    res.json({ success: true, settings: req.body });
  }
);

app.listen(3000, () => console.log('Server with schema validation running'));
